	private Optional<FactorCostEstimate> estimateLmdbFactorCost(TupleExpr factor, Set<String> currentlyBoundVars,
			double knownOutputRows) {
		if (factor == null) {
			return Optional.empty();
		}
		Set<String> boundVars = currentlyBoundVars == null ? Set.of() : currentlyBoundVars;
		if (factor instanceof Join join) {
			return estimateJoinFactorCost(join, boundVars);
		}
		double outputRows = isFiniteNonNegative(knownOutputRows) ? knownOutputRows
				: estimateFactorOutputRows(factor, boundVars);
		if (!Double.isFinite(outputRows) || outputRows < 0.0d) {
			return Optional.empty();
		}

		SketchBasedJoinEstimator.AccessShape accessShape = sketchBasedJoinEstimator
				.accessShapeForJoinOrdering(factor, boundVars);
		if (accessShape == null) {
			return Optional.of(new FactorCostEstimate(outputRows, outputRows));
		}

		Map<String, String> stringMetrics = new HashMap<>();
		Map<String, Double> doubleMetrics = new HashMap<>();
		AccessPathEstimate accessPathEstimate = chooseAccessPath(accessShape, outputRows);
		int prefixLength = accessPathEstimate == null ? 0 : accessPathEstimate.prefixLength();
		if (accessPathEstimate != null && prefixLength > 0) {
			stringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_NAME, accessPathEstimate.indexFieldSequence());
			doubleMetrics.put(TelemetryMetricNames.PLANNED_INDEX_PREFIX_LENGTH, (double) prefixLength);
		}
		stringMetrics.put(TelemetryMetricNames.PLANNED_LOOKUP_COMPONENTS,
				componentMaskString(accessPathEstimate == null ? accessShape.physicalLookupComponentMask()
						: accessPathEstimate.lookupComponentMask()));
		stringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE,
				accessMode(accessPathEstimate));
		int missingLookupComponentMask = accessPathEstimate == null ? accessShape.physicalLookupComponentMask()
				: accessPathEstimate.missingLookupComponentMask();
		if (missingLookupComponentMask != 0) {
			stringMetrics.put(TelemetryMetricNames.PLANNED_MISSING_LOOKUP_COMPONENTS,
					componentMaskString(missingLookupComponentMask));
		}

		if (accessPathEstimate != null) {
			doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_ROWS,
					accessPathEstimate.rowsBeforeFilterAtAccess());
			doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_PATH_CANDIDATES,
					(double) accessPathEstimate.candidateCount());
			if (isFiniteNonNegative(accessPathEstimate.rowsAfterFilterAtAccess())
					&& accessPathEstimate.rowsAfterFilterAtAccess() != accessPathEstimate.rowsBeforeFilterAtAccess()) {
				doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_ROWS_AFTER_FILTER,
						accessPathEstimate.rowsAfterFilterAtAccess());
			}
		}

		double workRows = accessPathEstimate == null ? outputRows : accessPathEstimate.workRowsPerInvocation();
		return Optional.of(new FactorCostEstimate(workRows, outputRows, stringMetrics, doubleMetrics));
	}

	private Optional<FactorCostEstimate> estimateJoinFactorCost(Join join, Set<String> boundVars) {
		Optional<FactorCostEstimate> leftEstimate = estimateLmdbFactorCost(join.getLeftArg(), boundVars);
		Set<String> rightBoundVars = unionBindingNames(boundVars, join.getLeftArg().getBindingNames());
		Optional<FactorCostEstimate> rightEstimate = estimateLmdbFactorCost(join.getRightArg(), rightBoundVars);
		if (leftEstimate.isEmpty() || rightEstimate.isEmpty()
				|| !isFiniteNonNegative(leftEstimate.get().getWorkRows())
				|| !isFiniteNonNegative(rightEstimate.get().getWorkRows())) {
			return Optional.empty();
		}

		double outputRows = estimateFactorOutputRows(join, boundVars);
		if (!isFiniteNonNegative(outputRows)) {
			outputRows = Math.max(leftEstimate.get().getOutputRows(), rightEstimate.get().getOutputRows());
		}
		return Optional.of(
				new FactorCostEstimate(leftEstimate.get().getWorkRows() + rightEstimate.get().getWorkRows(),
						outputRows));
	}

	private Set<String> unionBindingNames(Set<String> base, Set<String> additions) {
		if (base == null || base.isEmpty()) {
			return additions == null ? Set.of() : additions;
		}
		if (additions == null || additions.isEmpty()) {
			return base;
		}
		return new UnionBindingNameSet(base, additions);
	}

	private static final class UnionBindingNameSet extends AbstractSet<String> {
		private final Set<String> left;
		private final Set<String> right;
		private final int size;

		private UnionBindingNameSet(Set<String> left, Set<String> right) {
			this.left = left;
			this.right = right;
			int computedSize = left.size();
			for (String bindingName : right) {
				if (!left.contains(bindingName)) {
					computedSize++;
				}
			}
			this.size = computedSize;
		}

		@Override
		public Iterator<String> iterator() {
			Iterator<String> leftIterator = left.iterator();
			Iterator<String> rightIterator = right.iterator();
			return new Iterator<>() {
				private String nextRight;

				@Override
				public boolean hasNext() {
					if (leftIterator.hasNext()) {
						return true;
					}
					if (nextRight != null) {
						return true;
					}
					while (rightIterator.hasNext()) {
						String candidate = rightIterator.next();
						if (!left.contains(candidate)) {
							nextRight = candidate;
							return true;
						}
					}
					return false;
				}

				@Override
				public String next() {
					if (leftIterator.hasNext()) {
						return leftIterator.next();
					}
					if (nextRight != null || hasNext()) {
						String result = nextRight;
						nextRight = null;
						return result;
					}
					throw new java.util.NoSuchElementException();
				}
			};
		}

		@Override
		public boolean contains(Object value) {
			return left.contains(value) || right.contains(value);
		}

		@Override
		public int size() {
			return size;
		}
	}

	private String accessMode(AccessPathEstimate accessPathEstimate) {
		if (accessPathEstimate == null || accessPathEstimate.prefixLength() <= 0) {
			return "fullScan";
		}
		return accessPathEstimate.directLookup() ? "directLookup" : "prefixScan";
	}

	private double estimateFactorOutputRows(TupleExpr factor, Set<String> boundVars) {
		double sketchRows = sketchBasedJoinEstimator.factorOutputRowsForJoinOrdering(factor, boundVars);
		if (isFiniteNonNegative(sketchRows)) {
			return sketchRows;
		}
		if (factor instanceof BindingSetAssignment assignment) {
			double rows = 0.0d;
			for (Object ignored : assignment.getBindingSets()) {
				rows += 1.0d;
			}
			return rows;
		}
		return getCardinality(factor);
	}

	private boolean canApplyFilterAtAccess(SketchBasedJoinEstimator.AccessShape accessShape,
			int prefixComponentMask) {
		int filterLookupComponentMask = accessShape.filterLookupComponentMask();
		if (filterLookupComponentMask == 0) {
			return false;
		}
		return (prefixComponentMask & filterLookupComponentMask) == filterLookupComponentMask;
	}

	private String componentMaskString(int componentMask) {
		if (componentMask == 0) {
			return "[]";
		}
		StringBuilder builder = new StringBuilder("[");
		boolean first = true;
		for (Component component : Component.values()) {
			if ((componentMask & (1 << component.ordinal())) == 0) {
				continue;
			}
			if (!first) {
				builder.append(", ");
			}
			builder.append(component);
			first = false;
		}
		return builder.append(']').toString();
	}

	private boolean isFiniteNonNegative(double value) {
		return Double.isFinite(value) && value >= 0.0d;
	}

	private AccessPathEstimate chooseAccessPath(SketchBasedJoinEstimator.AccessShape accessShape,
			double factorRows) {
		AccessPathEstimate bestEstimate = null;
		List<AccessPathCandidate> candidates = accessPathCandidates(accessShape);
		int candidateCount = candidates.size();
		int desiredLookupComponentMask = desiredLookupComponentMask(accessShape);
		for (AccessPathCandidate candidate : candidates) {
			double rowsBefore = accessShape.estimateAccessRows(candidate.prefixComponentMask());
			if (!isFiniteNonNegative(rowsBefore)) {
				continue;
			}
			double rowsAfter = rowsBefore;
			if (canApplyFilterAtAccess(accessShape, candidate.prefixComponentMask())
					&& isFiniteNonNegative(accessShape.filterMultiplier())
					&& accessShape.filterMultiplier() < 1.0d) {
				rowsAfter = rowsBefore * accessShape.filterMultiplier();
			}
			if (isFiniteNonNegative(factorRows)) {
				rowsAfter = Math.min(rowsAfter, factorRows);
			}
			if (!isFiniteNonNegative(rowsAfter)) {
				continue;
			}
			boolean directLookup = candidate.missingLookupComponentMask() == 0;
			double workRows = directLookup ? Math.max(DIRECT_LOOKUP_WORK_ROW_FLOOR, rowsBefore) : rowsBefore;
			if (!isFiniteNonNegative(workRows)) {
				continue;
			}
			AccessPathEstimate estimate = new AccessPathEstimate(workRows, rowsBefore, rowsAfter,
					candidate.indexFieldSequence(), candidate.prefixLength(), candidate.prefixComponentMask(),
					directLookup, candidate.lookupComponentMask(), candidate.missingLookupComponentMask(),
					candidateCount);
			if (bestEstimate == null || compareAccessPathEstimate(estimate, bestEstimate) < 0) {
				bestEstimate = estimate;
			}
		}
		if (bestEstimate != null) {
			return bestEstimate;
		}
		return isFiniteNonNegative(factorRows)
				? new AccessPathEstimate(factorRows, factorRows, factorRows, "", 0, 0, false,
						desiredLookupComponentMask, desiredLookupComponentMask,
						candidateCount)
				: null;
	}

	private List<AccessPathCandidate> accessPathCandidates(SketchBasedJoinEstimator.AccessShape accessShape) {
		int patternConstantComponentMask = accessShape.patternConstantComponentMask();
		int variableLookupComponentMask = desiredLookupComponentMask(accessShape) & ~patternConstantComponentMask;
		Map<String, AccessPathCandidate> dedupedCandidates = new LinkedHashMap<>();
		for (int variableLookupMask : effectiveLookupVariableMasks(variableLookupComponentMask)) {
			int effectiveLookupMask = patternConstantComponentMask | variableLookupMask;
			for (TripleStore.IndexAccessPath candidate : tripleStore.indexAccessPaths(effectiveLookupMask)) {
				String candidateKey = candidate.indexFieldSequence() + '#' + candidate.prefixComponentMask();
				AccessPathCandidate accessPathCandidate = new AccessPathCandidate(candidate.indexFieldSequence(),
						candidate.prefixLength(), candidate.prefixComponentMask(), effectiveLookupMask,
						effectiveLookupMask & ~candidate.prefixComponentMask());
				AccessPathCandidate existingCandidate = dedupedCandidates.get(candidateKey);
				if (existingCandidate == null || Integer.bitCount(accessPathCandidate.lookupComponentMask()) > Integer
						.bitCount(existingCandidate.lookupComponentMask())) {
					dedupedCandidates.put(candidateKey, accessPathCandidate);
				}
			}
		}
		return List.copyOf(dedupedCandidates.values());
	}

	private int desiredLookupComponentMask(SketchBasedJoinEstimator.AccessShape accessShape) {
		return accessShape.physicalLookupComponentMask();
	}

	private List<Integer> effectiveLookupVariableMasks(int variableLookupComponentMask) {
		List<Integer> masks = new ArrayList<>();
		for (int mask = variableLookupComponentMask;; mask = (mask - 1) & variableLookupComponentMask) {
			masks.add(mask);
			if (mask == 0) {
				break;
			}
		}
		masks.sort(Collections.reverseOrder(Integer::compare));
		return masks;
	}

	private int compareAccessPathEstimate(AccessPathEstimate left, AccessPathEstimate right) {
		int workComparison = Double.compare(left.workRowsPerInvocation(), right.workRowsPerInvocation());
		if (workComparison != 0) {
			return workComparison;
		}
		int leftCoverage = Integer.bitCount(left.prefixComponentMask() & ~left.missingLookupComponentMask());
		int rightCoverage = Integer.bitCount(right.prefixComponentMask() & ~right.missingLookupComponentMask());
		int coverageComparison = Integer.compare(rightCoverage, leftCoverage);
		if (coverageComparison != 0) {
			return coverageComparison;
		}
		int prefixComparison = Integer.compare(right.prefixLength(), left.prefixLength());
		if (prefixComparison != 0) {
			return prefixComparison;
		}
		return 0;
	}

